function validateOrderRequest(req: OrderRequest | null): asserts req is OrderRequest {
  if (!req) throw new Error('null request');
  if (req.items.length === 0) throw new Error('empty order');
}

function calculateTotal(items: OrderItem[]): number {
  return items.reduce((sum, i) => sum + i.price * i.qty, 0);
}

async function processOrder(req: OrderRequest | null): Promise<string> {
  validateOrderRequest(req);
  const customer = await db.customers.findById(req.customerId);
  if (!customer) throw new Error('customer not found');
  const order = new Order({ customer, total: calculateTotal(req.items) });
  await db.orders.save(order);
  await mailer.send(order);
  return order.id;
}
